INSERT INTO ROUTING (ROUTING_ID, ITEM_ID, PROCESS_ID, PROCESS_SEQ, EQUIPMENT_ID, USE_YN, REMARK, CREATED_AT, UPDATED_AT)
SELECT SEQ_ROUTING.NEXTVAL, (SELECT ITEM_ID FROM ITEM WHERE ITEM_CODE = 'FG-CAM-001'), (SELECT PROCESS_ID FROM PROCESS WHERE PROCESS_CODE = 'PC-MIX'), 1, (SELECT EQUIPMENT_ID FROM EQUIPMENT WHERE EQUIPMENT_CODE = 'EQ-MIX-001'), 'Y', '표준 라우팅', TO_DATE('2026-04-10', 'YYYY-MM-DD'), TO_DATE('2026-04-10', 'YYYY-MM-DD')
